param([string]$RepoRoot='.',[Parameter(Mandatory=$true)][string]$FeatureId,[ValidateSet('todo','doing','blocked','review','done','dropped')][string]$Status='doing',[string]$CurrentStep='',[string]$NextStep='',[string]$Evidence='',[switch]$Json)
. "$PSScriptRoot\Common-AgentDevKit.ps1"
$root=Resolve-AgentDevKitRepoRoot $RepoRoot; $path=Join-Path $root '.agent-dev-kit/progress/progress-board.json'; if(-not(Test-Path -LiteralPath $path)){& "$PSScriptRoot\init-progress-board.ps1" -RepoRoot $root -Json|Out-Null}
$board=Get-Content -Raw -LiteralPath $path|ConvertFrom-Json; $found=$false; foreach($f in $board.features){ if($f.featureId -eq $FeatureId){$f.status=$Status; if($CurrentStep){$f.currentStep=$CurrentStep}; if($NextStep){$f.nextStep=$NextStep}; if($Evidence){$arr=@($f.evidence);$arr+=$Evidence;$f.evidence=$arr}; $found=$true}}
if(-not $found){$features=@($board.features);$features += [ordered]@{featureId=$FeatureId;title="New feature $FeatureId";mvp=$true;status=$Status;owner='agent';linkedSpec='spec/IMPLEMENTATION_PLAN.md';linkedTests=@();currentStep=$CurrentStep;nextStep=$NextStep;evidence=if($Evidence){@($Evidence)}else{@()}}; $board.features=$features}
$board.updatedAt=(Get-Date).ToString('o'); if($Status -eq 'doing'){$board.activeFeature=$FeatureId}; $board|ConvertTo-Json -Depth 10|Set-Content -Encoding UTF8 -LiteralPath $path; & "$PSScriptRoot\show-progress-board.ps1" -RepoRoot $root | Set-Content -Encoding UTF8 -LiteralPath (Join-Path $root '.agent-dev-kit/progress/PROGRESS_BOARD.md')
Write-AgentDevKitJson -Json:$Json -Data @{ok=$true;featureId=$FeatureId;status=$Status;board=$path}
